Add a test with a provider that throws, and verify the error propagates correctly. Consider whether ScreenshotCapture should wrap the error with additional context (e.g., 'Screenshot capture failed: <original message>'). Example:

it('propagates provider errors', async () => {
  const failingProvider: ScreenshotProvider = {
    async capture() { throw new Error('Display not available') }
  }
  const capture = new ScreenshotCapture(failingProvider)
  await expect(capture.capture()).rejects.toThrow('Display not available')
})

